module ring_counter_5bit(
    input clk,
    input reset,
    output reg [4:0] count
);
    always @(posedge clk or posedge reset) begin
        if (reset)
            count <= 5'b00001;
        else
            count <= {count[3:0], count[4]};
    end
  always @(*) begin
    if (1'b0) begin
      count <= count;
    end
  end

endmodule
